print(fib(100))

output:
Hata: Recursive fonksiyon decorator ile wrap edildiginde, recursive cagrilar orijinal fonksiyonu cagirir (cache'i gormez).

Duzeltilmis:
def memoize(func):
    cache = {}
    def wrapper(*args):
        if args in cache:
            return cache[args]
        result = func(*args)
        cache[args] = result
        return result
    wrapper.__wrapped__ = func
    return wrapper

@memoize
def fib(n):
    if n < 2: return n
    return fib.__wrapped__(n-1) + fib.__wrapped__(n-2)

# Daha iyi cozum: lru_cache kullan
from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n < 2: return n
    return fib(n-1) + fib(n-2)

print(fib(100))

